const quotations = $input.all().map(item => item.json);
if (!quotations || quotations.length === 0) {
  return [{ json: { error: 'No quotations found', rfq_id: $('Webhook').first().json.rfq_id } }];
}

const prices = quotations.map(q => parseFloat(q.total_amount));
const deliveries = quotations.map(q => parseInt(q.delivery_days));
const minPrice = Math.min(...prices);
const minDelivery = Math.min(...deliveries);

const scored = quotations.map(q => {
  const priceScore = (minPrice / parseFloat(q.total_amount)) * 100;
  const deliveryScore = (minDelivery / parseInt(q.delivery_days)) * 100;
  const ratingScore = (parseFloat(q.vendors?.rating || 3) / 5) * 100;
  const composite = (priceScore * 0.40) + (deliveryScore * 0.25) + (ratingScore * 0.35);
  return {
    vendor_id: q.vendor_id,
    vendor_name: q.vendors?.company_name || 'Unknown',
    total_amount: parseFloat(q.total_amount),
    delivery_days: parseInt(q.delivery_days),
    rating: parseFloat(q.vendors?.rating || 3),
    price_score: Math.round(priceScore * 100) / 100,
    delivery_score: Math.round(deliveryScore * 100) / 100,
    rating_score: Math.round(ratingScore * 100) / 100,
    composite_score: Math.round(composite * 100) / 100
  };
}).sort((a, b) => b.composite_score - a.composite_score);

return [{ json: { rfq_id: $('Webhook').first().json.rfq_id, scored } }];

