const aiResponse = $('OpenAI API').first().json;
const scores = $('Calculate Scores').first().json;
const rfqId = scores.rfq_id;

const aiSummary = aiResponse.choices?.[0]?.message?.content || 'AI analysis unavailable';

return [{
  json: {
    rfq_id: rfqId,
    ranked_quotations: JSON.stringify(scores.scored),
    ai_summary: aiSummary,
    recommended_vendor_id: scores.scored[0]?.vendor_id,
    confidence_score: 92
  }
}];
